import React, { useState } from 'react';
import './Login.css';

export default function Login({ onLogin, onNavigate }) {
	const [email, setEmail] = useState('');
	const [password, setPassword] = useState('');
	const [message, setMessage] = useState('');

	const handleSubmit = () => {
		const result = onLogin({ email, password });
		setMessage(result.message);

		if (result.success) {
			onNavigate('/account');
		}
	};

	return (
		<section className="page auth-page">
			<header className="page__header">
				<h1 className="page__title">Connexion</h1>
				<p className="page__subtitle">Accédez à votre espace client Althea Medical.</p>
			</header>

			<div className="form-grid">
				<input className="input" placeholder="Adresse e-mail" value={email} onChange={(event) => setEmail(event.target.value)} />
				<input className="input" type="password" placeholder="Mot de passe" value={password} onChange={(event) => setPassword(event.target.value)} />
			</div>

			<div className="notice notice--info">
				Mot de passe oublié : le flux de réinitialisation sera branché côté backend avec e-mail sécurisé.
			</div>
			{message ? <div className={`notice ${message.includes('réussie') ? 'notice--success' : 'notice--warning'}`}>{message}</div> : null}

			<div className="page-actions">
				<button className="btn btn--secondary auth-action" type="button" onClick={() => onNavigate('/register')}>Créer un compte</button>
				<button className="btn btn--primary auth-action" type="button" onClick={handleSubmit}>Se connecter</button>
			</div>
		</section>
	);
}
